import json
from elasticsearch import Elasticsearch, RequestsHttpConnection

es = Elasticsearch(
    hosts=['localhost'],
    connection_class=RequestsHttpConnection
)

def execute_script(script):
    # Check if the script is valid JSON
    try:
        json.loads(script)
    except ValueError:
        raise ValueError('Invalid JSON script')

    # Enable inline scripts in cluster config
    es.cluster.put_settings(body={'transient': {'script.inline': 'true'}})

    # Execute the script using Elasticsearch Script API
    response = es.search(index='*', body={
        'aggs': {
            'my_agg': {
                'terms': {
                    'field': 'my_field'
                },
                'script': {
                    'lang': 'painless',
                    'source': script
                }
            }
        }
    })

    # Disable inline scripts in cluster config
    es.cluster.put_settings(body={'transient': {'script.inline': 'false'}})

    return response